152	};
153	
154	function citationKind(citation: PublicCitation): string {
155	  const kind = citation.source_kind.trim().toLowerCase();
156	  if (kind === "claim") return "opinion";
157	  if (kind === "conclusion") return "firm conclusion";
158	  return kind || "firm source";
159	}
160	
161	function citationTitle(citation: CitationWithVisibility): string {
162	  return (
163	    citation.conclusion_title?.trim() ||
164	    citation.conclusionTitle?.trim() ||
165	    citationKind(citation)
166	  );
167	}
168	
169	function normalizedVisibility(citation: CitationWithVisibility): string {
170	  return (citation.source_visibility ?? citation.visibility ?? "")
171	    .trim()
172	    .toLowerCase()
173	    .replace(/-/g, "_");
174	}
175	
176	function canExposePublicUrl(citation: CitationWithVisibility, publicUrl: string | null): boolean {
177	  return Boolean(publicUrl?.trim()) && normalizedVisibility(citation) === "org";
178	}
179	
180	function safeHref(rawUrl: string | null): string | null {
181	  const trimmed = rawUrl?.trim();
182	  if (!trimmed) return null;
183	  if (trimmed.startsWith("/") && !trimmed.startsWith("//")) return trimmed;
184	  try {
185	    const url = new URL(trimmed);
186	    if (url.protocol === "http:" || url.protocol === "https:") return url.toString();
187	  } catch {
188	    return null;
189	  }
190	  return null;
191	}
192	
193	function isHTMLElement(value: unknown): value is HTMLElement {
194	  if (!value || typeof value !== "object") return false;
195	  if (typeof HTMLElement === "undefined") {
196	    return typeof (value as HTMLElement).focus === "function";
197	  }
198	  return value instanceof HTMLElement;
199	}
200	
201	function focusableElements(container: HTMLElement): HTMLElement[] {
202	  return Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR)).filter(
203	    (element) => !element.hasAttribute("disabled") && element.tabIndex !== -1,
204	  );
205	}
206	
207	function anchorIsOutsideViewport(anchor: HTMLElement): boolean {
208	  const rect = anchor.getBoundingClientRect();
209	  const viewportWidth =
210	    window.innerWidth || document.documentElement?.clientWidth || WIDTH;
211	  const viewportHeight =
212	    window.innerHeight || document.documentElement?.clientHeight || ESTIMATED_HEIGHT;
213	  return (
214	    rect.bottom < 0 ||
215	    rect.top > viewportHeight ||
216	    rect.right < 0 ||
217	    rect.left > viewportWidth
218	  );
219	}
220	
221	function positionFor(anchor: HTMLElement, dialog: HTMLElement | null): PopoverPosition {
222	  const rect = anchor.getBoundingClientRect();
223	  const viewportWidth =
224	    window.innerWidth || document.documentElement?.clientWidth || WIDTH + MARGIN * 2;
225	  const viewportHeight =
226	    window.innerHeight || document.documentElement?.clientHeight || ESTIMATED_HEIGHT;
227	  const height = dialog?.offsetHeight || ESTIMATED_HEIGHT;
228	  const preferredTop = rect.top - height - 10;
229	  const top =
230	    preferredTop >= MARGIN
231	      ? preferredTop
232	      : Math.min(rect.bottom + 10, Math.max(MARGIN, viewportHeight - height - MARGIN));
233	  const centeredLeft = rect.left + rect.width / 2 - WIDTH / 2;
234	  const left = Math.min(
235	    Math.max(MARGIN, centeredLeft),
236	    Math.max(MARGIN, viewportWidth - WIDTH - MARGIN),
237	  );
238	  return { left, top };
239	}
240	
241	interface CitationVerdictPillProps {
242	  verdict: CitationVerdictPayload;
243	}
244	
245	function CitationVerdictPill({ verdict }: CitationVerdictPillProps) {
246	  const style = verdictPill(verdict.relation_holds);
247	  const overridden = Boolean(verdict.overridden_by && verdict.override_reason);
248	  const summary = verdictSummary(verdict);
249	  return (
250	    <div
251	      data-testid="citation-verdict"
252	      data-verdict={verdict.relation_holds}
253	      style={{ marginTop: "0.4rem" }}
254	      title={summary}
255	    >
256	      <span
257	        aria-label={`Citation verdict: ${style.label}`}
258	        data-testid="citation-verdict-pill"
259	        style={{
260	          background: style.bg,
261	          border: "1px solid rgba(0,0,0,0.35)",
262	          borderRadius: "999px",
263	          color: style.fg,
264	          display: "inline-block",
265	          fontFamily: "'IBM Plex Mono', monospace",
266	          fontSize: "0.65rem",
267	          letterSpacing: "0.1em",
268	          padding: "0.15rem 0.55rem",
269	          textTransform: "uppercase",
270	        }}
271	      >
272	        {style.label}
273	      </span>
274	      {overridden ? (
275	        <span
276	          style={{
277	            color: "var(--currents-muted)",
278	            fontSize: "0.7rem",
279	            marginLeft: "0.5rem",
280	          }}
281	        >
282	          founder override
283	        </span>
284	      ) : null}
285	      <p
286	        style={{
287	          color: "var(--currents-parchment-dim)",
288	          fontSize: "0.72rem",
289	          lineHeight: 1.4,
290	          margin: "0.35rem 0 0",
291	        }}
292	      >
293	        {summary}
294	      </p>
295	    </div>
296	  );
297	}
298	
299	interface CredibilityStripProps {
300	  credibility: SourceCredibilityPayload;
301	}
302	
303	function CredibilityStrip({ credibility }: CredibilityStripProps) {
304	  const score = Math.max(0, Math.min(100, credibility.score_100));
305	  const fill = scoreBandColor(score);
306	  const bandLabel = scoreBandLabel(score);
307	  const summary = summaryLine(credibility);
308	  const tooltip = credibility.confident
309	    ? summary
310	    : `${summary} — ${unconfidentCaveat(credibility)}`;
311	
312	  return (
313	    <div
314	      data-testid="source-credibility"
315	      style={{
316	        borderTop: "1px solid var(--currents-border)",
317	        marginTop: "0.7rem",
318	        paddingTop: "0.55rem",
319	      }}
320	      title={tooltip}
321	    >
322	      <div
323	        style={{
324	          alignItems: "baseline",
325	          color: "var(--currents-muted)",
326	          display: "flex",
327	          fontFamily: "'IBM Plex Mono', monospace",
328	          fontSize: "0.65rem",
329	          justifyContent: "space-between",
330	          letterSpacing: "0.1em",
331	          textTransform: "uppercase",
332	        }}
333	      >
334	        <span>Source credibility</span>
335	        <span style={{ color: "var(--currents-parchment-dim)" }}>
336	          {sourceTypeLabel(credibility.source_type)}
337	        </span>
338	      </div>
339	      <div
340	        aria-label={
341	          credibility.confident
342	            ? `Source credibility ${score} of 100 (${bandLabel})`
343	            : `Source credibility unsettled — ${credibility.n_updates} of ${credibility.min_updates_for_confidence} updates`
344	        }
345	        role="img"
346	        style={{
347	          background: "rgba(255,255,255,0.06)",
348	          borderRadius: "3px",
349	          height: "8px",
350	          marginTop: "0.35rem",
351	          overflow: "hidden",
352	          position: "relative",
353	          width: "100%",
354	        }}
355	      >
356	        <div
357	          data-testid="source-credibility-fill"
358	          style={{
359	            background: credibility.confident ? fill : "rgba(255,255,255,0.18)",
360	            height: "100%",
361	            transition: "width 200ms ease",
362	            width: `${score}%`,
363	          }}
364	        />
365	      </div>
366	      <div
367	        style={{
368	          color: "var(--currents-parchment-dim)",
369	          display: "flex",
370	          fontFamily: "'IBM Plex Mono', monospace",
371	          fontSize: "0.7rem",
372	          justifyContent: "space-between",
373	          marginTop: "0.3rem",
374	        }}
375	      >
376	        <span data-testid="source-credibility-score">
377	          {credibility.confident
378	            ? `${score.toFixed(score % 1 === 0 ? 0 : 1)} / 100`
379	            : `n=${credibility.n_updates} updates`}
380	        </span>
381	        <span style={{ color: "var(--currents-muted)" }}>{summary}</span>
382	      </div>
383	      {!credibility.confident ? (
384	        <p
385	          style={{
386	            color: "var(--currents-muted)",
387	            fontSize: "0.72rem",
388	            lineHeight: 1.4,
389	            margin: "0.35rem 0 0",
390	          }}
391	        >
392	          {unconfidentCaveat(credibility)}
393	        </p>
394	      ) : null}
395	    </div>
396	  );
397	}
398	
399	export default function CitationPopover({
400	  open,
401	  onClose,
402	  anchorRef,
403	  citation,
404	  conclusionText,
405	  publicUrl,
406	  id,
407	}: CitationPopoverProps) {
408	  const rawId = useId();
409	  const popoverId = id ?? `citation-popover-${rawId.replace(/:/g, "")}`;
410	  const dialogRef = useRef<HTMLDivElement | null>(null);
411	  const [position, setPosition] = useState<PopoverPosition | null>(null);
412	  const href = canExposePublicUrl(citation, publicUrl) ? safeHref(publicUrl) : null;
413	  const text =
414	    conclusionText.trim() ||
415	    citation.quoted_span.trim() ||
416	    "Firm conclusion text unavailable.";
417	
418	  const updatePosition = useCallback(() => {
419	    const anchor = anchorRef.current;
420	    if (!anchor) {
421	      onClose();
422	      return;
423	    }
424	    if (anchorIsOutsideViewport(anchor)) {
425	      onClose();
426	      return;
427	    }
428	    setPosition(positionFor(anchor, dialogRef.current));
429	  }, [anchorRef, onClose]);
430	
431	  useEffect(() => {
432	    if (!open) return;
433	    updatePosition();
434	    window.addEventListener("resize", updatePosition);
435	    window.addEventListener("scroll", updatePosition, true);
436	    return () => {
437	      window.removeEventListener("resize", updatePosition);
438	      window.removeEventListener("scroll", updatePosition, true);
439	    };
440	  }, [open, updatePosition]);
441	
442	  useEffect(() => {
443	    if (!open) return;
444	
445	    const handlePointerDown = (event: MouseEvent | TouchEvent) => {
446	      const target = event.target as Node | null;
447	      if (!target) return;
448	      if (dialogRef.current?.contains(target)) return;
449	      if (anchorRef.current?.contains(target)) return;
450	      onClose();
451	    };
452	
453	    const handleKeyDown = (event: KeyboardEvent) => {
454	      if (event.key === "Escape") {
455	        event.preventDefault();
456	        onClose();
457	      }
458	    };
459	
460	    document.addEventListener("mousedown", handlePointerDown);
461	    document.addEventListener("touchstart", handlePointerDown);
462	    document.addEventListener("keydown", handleKeyDown);
463	    return () => {
464	      document.removeEventListener("mousedown", handlePointerDown);
465	      document.removeEventListener("touchstart", handlePointerDown);
466	      document.removeEventListener("keydown", handleKeyDown);
467	    };
468	  }, [anchorRef, onClose, open]);
469	
470	  useEffect(() => {
471	    if (!open) return;
472	    const previousFocus = document.activeElement;
473	    const frame = window.requestAnimationFrame(() => {
474	      const dialog = dialogRef.current;
475	      if (!dialog) return;
476	      const [first] = focusableElements(dialog);
477	      (first ?? dialog).focus();
478	    });
479	
480	    return () => {
481	      window.cancelAnimationFrame(frame);
482	      if (isHTMLElement(previousFocus)) previousFocus.focus();
483	    };
484	  }, [open]);
485	
486	  const trapFocus = (event: ReactKeyboardEvent<HTMLDivElement>) => {
487	    if (event.key !== "Tab") return;
488	    const dialog = dialogRef.current;
489	    if (!dialog) return;
490	    const focusable = focusableElements(dialog);
491	    if (!focusable.length) {
492	      event.preventDefault();
493	      dialog.focus();
494	      return;
495	    }
496	
497	    const first = focusable[0];
498	    const last = focusable[focusable.length - 1];
499	    const active = document.activeElement;
500	    if (event.shiftKey && active === first) {
501	      event.preventDefault();
502	      last.focus();
503	    } else if (!event.shiftKey && active === last) {
504	      event.preventDefault();
505	      first.focus();
506	    }
507	  };
508	
509	  if (!open || typeof document === "undefined") return null;
510	
511	  const standing = normalizedStanding(citation);
512	  const standingMeta = standing === "active" ? null : STANDING_STYLE[standing];
513	  const reason = standingReason(citation);
514	  const credibility = normalizeCredibilityPayload(
515	    citation.source_credibility ?? citation.sourceCredibility ?? null,
516	  );
517	  const verdict = normalizeVerdictPayload(
518	    citation.citation_verdict ?? citation.citationVerdict ?? null,
519	  );
520	
521	  return createPortal(
522	    <div
523	      aria-modal="false"
524	      id={popoverId}
525	      onKeyDown={trapFocus}
526	      ref={dialogRef}
527	      role="dialog"
528	      style={{
529	        ...shellStyle,
530	        left: `${position?.left ?? MARGIN}px`,
531	        opacity: position ? 1 : 0,
532	        top: `${position?.top ?? MARGIN}px`,
533	      }}
534	      tabIndex={-1}
535	    >
536	      <div
537	        style={{
538	          alignItems: "start",
539	          display: "flex",
540	          gap: "0.75rem",
541	          justifyContent: "space-between",
542	        }}
543	      >
544	        <div>
545	          <div style={captionStyle}>{citationKind(citation)}</div>
546	          <h2 style={titleStyle}>{citationTitle(citation)}</h2>
547	          {standingMeta ? (
548	            <div style={{ marginTop: "0.4rem" }}>
549	              <span
550	                aria-label={`Source standing: ${standingMeta.label}`}
551	                data-testid="source-standing-pill"
552	                style={{
553	                  background: standingMeta.bg,
554	                  border: "1px solid rgba(0,0,0,0.35)",
555	                  borderRadius: "999px",
556	                  color: standingMeta.fg,
557	                  display: "inline-block",
558	                  fontFamily: "'IBM Plex Mono', monospace",
559	                  fontSize: "0.65rem",
560	                  letterSpacing: "0.1em",
561	                  padding: "0.15rem 0.55rem",
562	                  textTransform: "uppercase",
563	                }}
564	              >
565	                {standingMeta.label}
566	              </span>
567	              {reason ? (
568	                <span
569	                  style={{
570	                    color: "var(--currents-muted)",
571	                    fontSize: "0.72rem",
572	                    marginLeft: "0.55rem",
573	                  }}
574	                >
575	                  {reason}
576	                </span>
577	              ) : null}
578	              {standing === "retracted" || standing === "corrected" ? (
579	                <a
580	                  href="/methodology#source-standing"
581	                  style={{
582	                    color: "var(--currents-gold)",
583	                    display: "inline-block",
584	                    fontSize: "0.72rem",
585	                    marginLeft: "0.55rem",
586	                    textDecoration: "underline",
587	                  }}
588	                >
589	                  this source has been retracted →
590	                </a>
591	              ) : null}
592	            </div>
593	          ) : null}
594	          {verdict ? <CitationVerdictPill verdict={verdict} /> : null}
595	        </div>
596	        <button
597	          aria-label="Close citation"
598	          onClick={onClose}
599	          style={{
600	            background: "transparent",
601	            border: "1px solid var(--currents-border)",
602	            borderRadius: "4px",
603	            color: "var(--currents-parchment-dim)",
604	            cursor: "pointer",
605	            fontSize: "0.8rem",
606	            lineHeight: 1,
607	            padding: "0.25rem 0.35rem",
608	          }}
609	          type="button"
610	        >
611	          ×
612	        </button>
613	      </div>
614	
615	      {credibility ? (
616	        <CredibilityStrip credibility={credibility} />
617	      ) : null}
618	
619	      <div style={bodyStyle}>{renderSafeMarkdown(text)}</div>
620	
621	      {href ? (
622	        <a href={href} rel="noopener nofollow ugc" style={linkStyle} target="_blank">
623	          Open the public conclusion →
624	        </a>
625	      ) : (
626	        <p style={privateNoteStyle}>
627	          Source recorded by the firm; not publicly available.
628	        </p>
629	      )}
630	    </div>,
631	    document.body,
632	  );
633	}
